def maximize_sum_after_k_negations(nums, k):
    nums.sort()
    for i in range(len(nums)):
        if nums[i] < 0 and k > 0:
            nums[i] = -nums[i]
            k -= 1
        else:
            break

    if k % 2 != 0:
        nums.sort()
        nums[0] = -nums[0]

    return sum(nums)
